INSERT INTO pages (slug, title, updated, content) VALUES ('my-account', 'My Account', NULL, '<p class="lead">Manage your orders, view your license keys, update billing details, and access support tickets. Sign in to your Zed Webtech account for instant access to your purchase history and downloadable software.</p>');
INSERT INTO pages (slug, title, updated, content) VALUES ('help-center', 'Help Center', NULL, '<p class="lead">Browse our comprehensive knowledge base covering installation, activation, troubleshooting, and licensing. Find quick answers to common Microsoft Office, Windows and Antivirus questions, or contact our team Mon-Sat 9-6 EST.</p>');
INSERT INTO pages (slug, title, updated, content) VALUES ('installation-guide', 'Installation Guide', NULL, '<p class="lead">Step-by-step installation tutorials for Office 2024/2021/2019, Windows 10/11, Microsoft Project & Visio. Download links and activation key entry instructions for both PC and Mac.</p>');
INSERT INTO pages (slug, title, updated, content) VALUES ('activation-help', 'Activation Help', NULL, '<p class="lead">Having trouble activating your product? We provide free, hands-on activation assistance. Our specialists can guide you through Microsoft account redemption or remote-install your software via ProAssist.</p>');
INSERT INTO pages (slug, title, updated, content) VALUES ('faqs', 'FAQs', NULL, '<p class="lead">Frequently asked questions about our licenses, delivery times, refund policies and supported devices. All keys are genuine and Microsoft-verified.</p>');
INSERT INTO pages (slug, title, updated, content) VALUES ('contact-us', 'Contact Us', NULL, '<p class="lead">Reach our team anytime via phone, email or live chat. Phone: 1-888-632-9902 • Email: Reachout@zedwebtech.com • Hours: Monday-Saturday, 9 AM-6 PM EST.</p>');
INSERT INTO pages (slug, title, updated, content) VALUES ('returns-refunds', 'Returns & Refunds', NULL, '<p class="lead">30-day money-back guarantee on all unactivated licenses. If you experience issues we cannot resolve, we''ll issue a full refund — no questions asked. Submit a refund request from your account.</p>');
INSERT INTO pages (slug, title, updated, content) VALUES ('why-choose-us', 'Why Choose Us', NULL, '<p class="lead">5+ years serving 50,000+ customers worldwide with genuine Microsoft licenses, instant digital delivery, expert support and a 30-day guarantee. Authorized reseller — every key verified.</p>');
INSERT INTO pages (slug, title, updated, content) VALUES ('customer-reviews', 'Customer Reviews', NULL, '<p class="lead">4.6/5 from 5,519+ verified Shopper Approved reviews. Read what our customers say about authenticity, delivery speed, and support quality.</p>');
INSERT INTO pages (slug, title, updated, content) VALUES ('affiliate-program', 'Affiliate Program', NULL, '<p class="lead">Earn competitive commissions promoting genuine Microsoft software. Industry-leading payouts, real-time tracking, marketing assets and dedicated affiliate managers. Apply today.</p>');

-- Blog posts
INSERT INTO blog_posts (id, title, date, read_time, image, content) VALUES ('why-upgrade-office-2024', 'Why You Should Upgrade to Microsoft Office 2024 Today', 'Mar 18, 2026', '5 min read', 'https://images.pexels.com/photos/2102416/pexels-photo-2102416.jpeg', '<p>Microsoft Office 2024 is the newest perpetual-license release, and it brings meaningful upgrades for anyone still on Office 2019 or 2016.</p><h2 class="h5 fw-bold mt-4">A one-time purchase, no subscription</h2><p>Unlike Microsoft 365, Office 2024 is yours forever with a single payment. For home users and businesses that do not need cloud-first features, this remains the most economical option over a 3-5 year horizon.</p><h2 class="h5 fw-bold mt-4">Performance and new features</h2><p>Office 2024 includes faster startup times, improved Excel dynamic arrays and new functions, refreshed visuals across Word and PowerPoint, and better accessibility tooling. It is fully optimized for Windows 11 and the newest macOS releases.</p><h2 class="h5 fw-bold mt-4">Security support window</h2><p>Buying the newest perpetual release maximizes your support window for security updates, keeping your installation protected for years to come.</p><p>Ready to upgrade? Browse our genuine Office 2024 licenses with instant digital delivery.</p>');
INSERT INTO blog_posts (id, title, date, read_time, image, content) VALUES ('office-2019-vs-2021-mac', 'Microsoft Office 2019 vs. 2021 for Mac: Which Version Should You Choose?', 'Jan 30, 2026', '5 min read', 'https://images.unsplash.com/photo-1649433391420-542fcd3835ea?q=80&w=870&auto=format&fit=crop', '<p>Choosing between Office 2019 and Office 2021 for Mac comes down to budget, macOS compatibility and feature needs.</p><h2 class="h5 fw-bold mt-4">Compatibility</h2><p>Office 2021 supports the latest macOS versions and Apple Silicon natively, while Office 2019 runs best on older macOS releases. If you own an M1/M2/M3 Mac, Office 2021 is the safer long-term choice.</p><h2 class="h5 fw-bold mt-4">Features</h2><p>Office 2021 adds Excel features like XLOOKUP and LET, refreshed dark mode support, and Line Focus in Word. Office 2019 still covers all core needs for documents, spreadsheets and email.</p><h2 class="h5 fw-bold mt-4">Price</h2><p>Office 2019 for Mac is the budget pick, often 20-30% cheaper. If your Mac is older and your needs are basic, it remains excellent value.</p><p>Both are available as genuine lifetime licenses in our store with instant delivery.</p>');
INSERT INTO blog_posts (id, title, date, read_time, image, content) VALUES ('home-business-2024-features', 'MS Office Home and Business 2024: Features for Modern Businesses', 'Jan 21, 2026', '11 min read', 'https://images.unsplash.com/photo-1632239776255-0a7f24814df2?q=80&w=871&auto=format&fit=crop', '<p>Microsoft Office Home & Business 2024 is built for small businesses and professionals who need Outlook alongside the core Office apps.</p><h2 class="h5 fw-bold mt-4">What is included</h2><p>Word, Excel, PowerPoint, OneNote and Outlook - licensed for commercial use on one PC or Mac. The Home edition omits Outlook and commercial-use rights, which is why Home & Business is the standard pick for businesses.</p><h2 class="h5 fw-bold mt-4">Why businesses choose it</h2><ul><li>One-time cost that is easy to budget per workstation</li><li>Commercial use rights included</li><li>Outlook for professional email, calendars and contacts</li><li>No forced cloud dependency - files stay local if you prefer</li></ul><h2 class="h5 fw-bold mt-4">Volume licensing</h2><p>Need 5+ seats? Contact our team for volume pricing and consolidated invoicing.</p>');

-- Testimonials
INSERT INTO testimonials (name, initials, location, product, text, rating) VALUES
('Brandon Koch', 'BK', 'Mn, USA', 'Microsoft Office', 'I ordered software from them and when it didn''t work I called the customer service and I could not understand the guy, he spoke very poor English and I couldn''t even understand what he said. So I just canceled it and then he didn''t want to refund me. I would not deal with them again.', 3),
('Alyssa Dickens', 'AD', 'USA', 'Microsoft Office', 'Overall the site was easy to use and had clear step-by-step instructions.', 5),
('ALBERT CHAPMAN', 'AC', 'New York, USA', 'Microsoft Office', 'I like the price. The only problem was that Microsoft stopped it from working and I had to get the company to fix the problem which they did in a timely manner.', 4),
('Mike H', 'MH', 'NH, USA', 'Microsoft Office', 'Easy to find the software I needed: Office & VISIO. The staff were amazing after I had some initial machine compatibility issues. They resolved everything so quickly. I''ve got a full set of current software. Mike', 5),
('bill delp', 'BD', 'USA', 'Microsoft Office', 'The software works. Had to load a new laptop.', 5),
('Dana', 'D', 'Nebraska, USA', 'Microsoft Office', 'I never got help and never got my software installed.', 2);

-- FAQs
INSERT INTO faqs (question, answer) VALUES
('Are these genuine Microsoft Office licenses?', 'Yes, all our licenses are genuine and sourced directly from authorized Microsoft distributors. Every license key is verified for authenticity before delivery.'),
('What is a perpetual license?', 'A perpetual license means you own the software forever with a one-time purchase. There are no recurring subscription fees, and you can use the software for as long as you want.'),
('How quickly will I receive my license key?', 'License keys are delivered via email within 15-30 minutes of successful payment confirmation. You will receive download instructions along with your activation key.'),
('Can I install this on multiple computers?', 'Each license is valid for one device. If you need licenses for multiple computers, please contact our sales team for volume discounts.'),
('What if I need technical support?', 'Our expert support team is available Monday through Saturday, 9 AM to 6 PM EST. We provide free professional support for installation, activation, and any issues you may encounter.'),
('Is my payment information secure?', 'Absolutely. Our checkout is SSL-encrypted and PCI-compliant. We never store your payment details on our servers and use trusted payment processors for all transactions.');

INSERT INTO pages (slug, title, updated, content) VALUES ('disclaimer', 'Disclaimer', 'January 1, 2026', '<h2 class="h5 fw-bold mt-4">Trademark Notice</h2><p>Microsoft&reg;, Windows&reg;, Office&reg;, Outlook&reg;, Xbox&reg;, and other Microsoft product names are trademarks or registered trademarks of Microsoft Corporation in the United States and/or other countries.</p><p>Trademarks, logos, brand names, product names, and company names mentioned on this website are the property of their respective owners and are used solely for identification and informational purposes. Use of these names, trademarks, and brands does not imply endorsement or affiliation.</p><h2 class="h5 fw-bold mt-4">Independent Service Provider</h2><p>The information, support, and services provided on this website are offered independently by Zed Webtech. Any references to Microsoft products or services are made solely to describe compatibility, support, troubleshooting, or informational content.</p><p>By using this website, you acknowledge and agree that Zed Webtech operates as an independent entity and does not represent Microsoft Corporation or any of its subsidiaries, affiliates, or partners.</p><p>Zed Webtech is an independent service provider and is not affiliated with, endorsed by, sponsored by, authorized by, or associated with Microsoft Corporation in any way.</p><h2 class="h5 fw-bold mt-4">Advertising &amp; Google Ads Policy Compliance</h2><p>Any paid advertisements (including Google Ads / PPC campaigns) operated by or on behalf of this website clearly identify us as an independent reseller and service provider. We do not claim to be Microsoft Corporation, an official Microsoft sales channel, or Microsoft-operated support in any advertising material.</p><p>In accordance with Google Ads policies on misrepresentation and third-party consumer technical support, we disclose that all software licenses sold and all support services offered on this website are provided independently. Customers may also obtain support directly from the original software manufacturer.</p><h2 class="h5 fw-bold mt-4">Accuracy of Information</h2><p>We strive to ensure all product descriptions, pricing, and availability information on this website are accurate. However, we reserve the right to correct any errors or inaccuracies and to update information at any time without prior notice. Prices and availability are subject to change without notice.</p><h2 class="h5 fw-bold mt-4">No Warranty</h2><p>The content on this website is provided &quot;as is&quot; without any warranties of any kind, either express or implied, including but not limited to implied warranties of merchantability, fitness for a particular purpose, or non-infringement. Zed Webtech does not warrant that this website will be uninterrupted or error-free.</p><h2 class="h5 fw-bold mt-4">Limitation of Liability</h2><p>To the fullest extent permitted by applicable law, Zed Webtech shall not be liable for any indirect, incidental, special, consequential, or punitive damages arising out of your access to or use of this website or any products or services purchased through it.</p><p>Some states within the United States do not allow the exclusion or limitation of certain damages; in such jurisdictions, our liability is limited to the maximum extent permitted by law.</p><h2 class="h5 fw-bold mt-4">Third-Party Links</h2><p>This website may contain links to third-party websites. These links are provided solely for your convenience. We have no control over the content of those sites and accept no responsibility for them or for any loss or damage that may arise from your use of them.</p><h2 class="h5 fw-bold mt-4">Contact</h2><p>If you have any questions about this Disclaimer, please contact us at <a href="mailto:Paynote@zedwebtech.com">Paynote@zedwebtech.com</a> or call <a href="tel:1-888-632-9902">1-888-632-9902</a>.</p>');

-- ============ Support tables + refreshed help pages (Jun 2026) ============

-- Support / contact form messages
CREATE TABLE IF NOT EXISTS support_messages (
  id INT AUTO_INCREMENT PRIMARY KEY,
  name VARCHAR(120) NOT NULL,
  email VARCHAR(190) NOT NULL,
  phone VARCHAR(40) DEFAULT '',
  order_number VARCHAR(40) DEFAULT '',
  subject VARCHAR(190) NOT NULL,
  message TEXT NOT NULL,
  source VARCHAR(20) DEFAULT 'contact',
  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

-- Customer refund requests (from returns.php)
CREATE TABLE IF NOT EXISTS refund_requests (
  id INT AUTO_INCREMENT PRIMARY KEY,
  order_number VARCHAR(40) NOT NULL,
  email VARCHAR(190) NOT NULL,
  status VARCHAR(20) DEFAULT 'pending',
  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);
UPDATE pages SET content = '<h2>Welcome to Our Help Center</h2>\n<p>Find answers to common questions and get the support you need for your software purchases.</p>\n\n<h3>Quick Links</h3>\n<ul>\n<li><a href=\"page.php?slug=installation-guide\"><strong>Installation Guide</strong></a> - Step-by-step installation instructions</li>\n<li><a href=\"page.php?slug=activation-help\"><strong>Activation Help</strong></a> - How to activate your software</li>\n<li><a href=\"page.php?slug=refund-policy\"><strong>Refund Policy</strong></a> - Our 30-day money-back guarantee</li>\n<li><a href=\"contact.php\"><strong>Contact Us</strong></a> - Get in touch with our team</li>\n</ul>\n\n<h2>Frequently Asked Questions</h2>\n\n<h3>Orders &amp; Delivery</h3>\n<p><strong>How will I receive my product?</strong> All products are delivered digitally via email. You will receive your license key and download instructions within minutes of purchase.</p>\n<p><strong>I haven\'t received my order. What should I do?</strong></p>\n<ul>\n<li>Check your spam/junk folder</li>\n<li>Verify the email address used at checkout</li>\n<li>Wait up to 24 hours for processing</li>\n<li>Contact our support team if you still haven\'t received it</li>\n</ul>\n<p><strong>Can I get a physical copy?</strong> We only offer digital delivery. No physical products are shipped.</p>\n\n<h3>Installation &amp; Activation</h3>\n<p><strong>How do I install my software?</strong> See our <a href=\"page.php?slug=installation-guide\">Installation Guide</a> for detailed step-by-step instructions.</p>\n<p><strong>My license key isn\'t working. What should I do?</strong></p>\n<ul>\n<li>Ensure you\'re entering the key correctly (no extra spaces)</li>\n<li>Make sure you\'re using the right version of the software</li>\n<li>Check our <a href=\"page.php?slug=activation-help\">Activation Help</a> page</li>\n<li>Contact support if issues persist</li>\n</ul>\n\n<h3>Payments &amp; Refunds</h3>\n<p><strong>What payment methods do you accept?</strong> We accept Visa, Mastercard, American Express, PayPal, Apple Pay, and Google Pay.</p>\n<p><strong>Can I get a refund?</strong> Yes, we offer a 30-day money-back guarantee. See our <a href=\"page.php?slug=refund-policy\">Refund Policy</a> for details, or start a request on the <a href=\"returns.php\">Return &amp; Refund</a> page.</p>\n\n<h2>Contact Support</h2>\n<p>Still need help? Our support team is ready to assist:</p>\n<ul>\n<li><strong>Email:</strong> <a href=\"mailto:Paynote@zedwebtech.com\">Paynote@zedwebtech.com</a></li>\n<li><strong>Phone:</strong> <a href=\"tel:1-888-632-9902\">1-888-632-9902</a></li>\n<li><strong>Live Chat:</strong> Available on our website</li>\n<li><strong>Hours:</strong> Monday-Friday, 9AM-6PM EST</li>\n</ul>\n<div class=\"card p-4 mt-4\"><h5 class=\"fw-bold mb-2\">Questions about this policy?</h5><p class=\"small text-secondary mb-2\">If you have any questions about this policy, please contact us.</p><p class=\"small mb-3\"><a href=\"mailto:Paynote@zedwebtech.com\">Paynote@zedwebtech.com</a> <span class=\"text-secondary mx-1\">|</span> <a href=\"tel:1-888-632-9902\">+1 888-632-9902</a></p><a href=\"index.php\" class=\"btn btn-sm btn-outline-primary rounded-pill align-self-start\">Back to Home</a></div>', updated = 'December 2024' WHERE slug = 'help-center';
UPDATE pages SET content = '<h2>Installation Guide</h2>\n<p>Follow these step-by-step instructions to install your software.</p>\n\n<h2>Before You Begin</h2>\n<h3>System Requirements</h3>\n<p>Ensure your computer meets the minimum requirements:</p>\n<p><strong>For Microsoft Office:</strong></p>\n<ul>\n<li>Windows 10 or later / macOS 10.14 or later</li>\n<li>4GB RAM (8GB recommended)</li>\n<li>4GB available disk space</li>\n<li>Internet connection for activation</li>\n</ul>\n<p><strong>For Windows OS:</strong></p>\n<ul>\n<li>1 GHz processor</li>\n<li>4GB RAM (8GB for Windows 11)</li>\n<li>64GB storage (Windows 11 requires 64GB+)</li>\n<li>DirectX 12 compatible graphics</li>\n</ul>\n\n<h2>Microsoft Office Installation</h2>\n<h3>Step 1: Download Office</h3>\n<ol>\n<li>Visit <a href=\"https://setup.office.com\" target=\"_blank\" rel=\"noopener\">setup.office.com</a></li>\n<li>Sign in with your Microsoft account (or create one)</li>\n<li>Enter your 25-character product key</li>\n<li>Click \"Install Office\"</li>\n</ol>\n<h3>Step 2: Run the Installer</h3>\n<ol>\n<li>Open the downloaded file</li>\n<li>Click \"Yes\" if prompted by User Account Control</li>\n<li>Wait for Office to download and install</li>\n<li>This may take 15-30 minutes depending on your internet speed</li>\n</ol>\n<h3>Step 3: Activate Office</h3>\n<ol>\n<li>Open any Office application (Word, Excel, etc.)</li>\n<li>Sign in with your Microsoft account</li>\n<li>Your license will be activated automatically</li>\n</ol>\n\n<h2>Windows Installation</h2>\n<h3>Step 1: Create Installation Media</h3>\n<ol>\n<li>Download the Windows Media Creation Tool from Microsoft</li>\n<li>Run the tool and select \"Create installation media\"</li>\n<li>Choose USB flash drive (8GB minimum)</li>\n<li>Follow the prompts to create bootable media</li>\n</ol>\n<h3>Step 2: Install Windows</h3>\n<ol>\n<li>Insert the USB drive and restart your computer</li>\n<li>Boot from the USB drive (press F12, F2, or Del during startup)</li>\n<li>Follow the Windows setup wizard</li>\n<li>Enter your product key when prompted</li>\n</ol>\n<h3>Step 3: Activate Windows</h3>\n<ol>\n<li>Go to Settings &gt; Update &amp; Security &gt; Activation</li>\n<li>Click \"Change product key\"</li>\n<li>Enter your 25-character license key</li>\n<li>Click \"Next\" to activate</li>\n</ol>\n\n<h2>Troubleshooting</h2>\n<h3>Common Issues</h3>\n<p><strong>\"Product key already used\" error</strong></p>\n<ul>\n<li>Ensure you\'re using a new, unused key</li>\n<li>Contact support if you purchased a new license</li>\n</ul>\n<p><strong>Installation stuck or frozen</strong></p>\n<ul>\n<li>Check your internet connection</li>\n<li>Disable antivirus temporarily</li>\n<li>Restart the installation</li>\n</ul>\n<p><strong>Activation failed</strong></p>\n<ul>\n<li>Verify your product key is entered correctly</li>\n<li>Ensure you have an internet connection</li>\n<li>See our <a href=\"page.php?slug=activation-help\">Activation Help</a> page</li>\n</ul>\n\n<h2>Need Help?</h2>\n<p>If you encounter any issues:</p>\n<ul>\n<li><strong>Email:</strong> <a href=\"mailto:Paynote@zedwebtech.com\">Paynote@zedwebtech.com</a></li>\n<li><strong>Phone:</strong> <a href=\"tel:1-888-632-9902\">1-888-632-9902</a></li>\n<li><strong>Live Chat:</strong> Available on our website</li>\n</ul>\n<div class=\"card p-4 mt-4\"><h5 class=\"fw-bold mb-2\">Questions about this policy?</h5><p class=\"small text-secondary mb-2\">If you have any questions about this policy, please contact us.</p><p class=\"small mb-3\"><a href=\"mailto:Paynote@zedwebtech.com\">Paynote@zedwebtech.com</a> <span class=\"text-secondary mx-1\">|</span> <a href=\"tel:1-888-632-9902\">+1 888-632-9902</a></p><a href=\"index.php\" class=\"btn btn-sm btn-outline-primary rounded-pill align-self-start\">Back to Home</a></div>', updated = 'December 2024' WHERE slug = 'installation-guide';
UPDATE pages SET content = '<h2>Activation Help</h2>\n<p>Having trouble activating your software? Follow these guides to resolve common activation issues.</p>\n\n<h2>Microsoft Office Activation</h2>\n<h3>Online Activation (Recommended)</h3>\n<ol>\n<li>Open any Office app (Word, Excel, PowerPoint)</li>\n<li>Sign in with your Microsoft account</li>\n<li>Go to File &gt; Account</li>\n<li>Click \"Change License\" or \"Activate Product\"</li>\n<li>Enter your 25-character product key</li>\n<li>Click \"Activate\" and follow the prompts</li>\n</ol>\n<h3>Phone Activation</h3>\n<p>If online activation fails:</p>\n<ol>\n<li>Open any Office app</li>\n<li>Go to File &gt; Account &gt; Activate Product</li>\n<li>Select \"I want to activate by telephone\"</li>\n<li>Call the number provided</li>\n<li>Follow the automated system to complete activation</li>\n</ol>\n\n<h2>Windows Activation</h2>\n<h3>Activate Windows Online</h3>\n<ol>\n<li>Open Settings (Windows key + I)</li>\n<li>Go to Update &amp; Security &gt; Activation</li>\n<li>Click \"Change product key\"</li>\n<li>Enter your 25-character license key</li>\n<li>Click \"Next\" to activate</li>\n</ol>\n<h3>Activate Windows by Phone</h3>\n<ol>\n<li>Open Command Prompt as Administrator</li>\n<li>Type: <code>slui 4</code> and press Enter</li>\n<li>Select your country</li>\n<li>Call the provided number</li>\n<li>Follow the automated prompts</li>\n</ol>\n\n<h2>Common Activation Errors</h2>\n<h3>\"Product key has already been used\"</h3>\n<p><strong>Possible causes:</strong></p>\n<ul>\n<li>Key was previously activated on another device</li>\n<li>Typing error when entering the key</li>\n</ul>\n<p><strong>Solutions:</strong></p>\n<ul>\n<li>Double-check the key is entered correctly</li>\n<li>If purchased from us, contact support with your order number</li>\n<li>We will verify and assist with activation</li>\n</ul>\n<h3>\"Product key is not valid\"</h3>\n<p><strong>Possible causes:</strong></p>\n<ul>\n<li>Incorrect product for the key</li>\n<li>Key entered with errors</li>\n</ul>\n<p><strong>Solutions:</strong></p>\n<ul>\n<li>Verify you\'re installing the correct product version</li>\n<li>Check for similar characters (0 vs O, 1 vs I)</li>\n<li>Remove any extra spaces</li>\n<li>Contact support if the issue persists</li>\n</ul>\n<h3>\"Unable to reach activation servers\"</h3>\n<p><strong>Solutions:</strong></p>\n<ul>\n<li>Check your internet connection</li>\n<li>Disable VPN if active</li>\n<li>Temporarily disable firewall/antivirus</li>\n<li>Try again later (servers may be busy)</li>\n</ul>\n\n<h2>Activation Limits</h2>\n<h3>How many devices can I activate?</h3>\n<table class=\"table table-bordered\" style=\"max-width:480px;\">\n<thead><tr><th>Product</th><th>Activation Limit</th></tr></thead>\n<tbody>\n<tr><td>Office Home</td><td>1 PC or Mac</td></tr>\n<tr><td>Office Professional</td><td>1 PC</td></tr>\n<tr><td>Windows 10/11</td><td>1 PC</td></tr>\n</tbody>\n</table>\n\n<h2>Contact Support</h2>\n<p>If you\'re still having activation issues:</p>\n<ul>\n<li><strong>Email:</strong> <a href=\"mailto:Paynote@zedwebtech.com\">Paynote@zedwebtech.com</a></li>\n<li><strong>Phone:</strong> <a href=\"tel:1-888-632-9902\">1-888-632-9902</a></li>\n<li><strong>Live Chat:</strong> Available on our website</li>\n</ul>\n<p><strong>Please have ready:</strong></p>\n<ul>\n<li>Your order number</li>\n<li>Product key (first 5 characters only)</li>\n<li>Error message received</li>\n</ul>\n<div class=\"card p-4 mt-4\"><h5 class=\"fw-bold mb-2\">Questions about this policy?</h5><p class=\"small text-secondary mb-2\">If you have any questions about this policy, please contact us.</p><p class=\"small mb-3\"><a href=\"mailto:Paynote@zedwebtech.com\">Paynote@zedwebtech.com</a> <span class=\"text-secondary mx-1\">|</span> <a href=\"tel:1-888-632-9902\">+1 888-632-9902</a></p><a href=\"index.php\" class=\"btn btn-sm btn-outline-primary rounded-pill align-self-start\">Back to Home</a></div>', updated = 'December 2024' WHERE slug = 'activation-help';

