UPDATE pages SET content = '<p class=\"lead\">Find answers to common questions and get the support you need for your software purchases.</p>\n\n<div class=\"row g-3 my-3\">\n  <div class=\"col-md-6\"><a href=\"page.php?slug=installation-guide\" class=\"card p-3 h-100 text-decoration-none d-flex flex-row align-items-center gap-3\"><i class=\"bi bi-download fs-3 text-primary\"></i><span><strong class=\"d-block\">Installation Guide</strong><small class=\"text-secondary\">Step-by-step installation instructions</small></span></a></div>\n  <div class=\"col-md-6\"><a href=\"page.php?slug=activation-help\" class=\"card p-3 h-100 text-decoration-none d-flex flex-row align-items-center gap-3\"><i class=\"bi bi-key-fill fs-3 text-success\"></i><span><strong class=\"d-block\">Activation Help</strong><small class=\"text-secondary\">How to activate your software</small></span></a></div>\n  <div class=\"col-md-6\"><a href=\"page.php?slug=refund-policy\" class=\"card p-3 h-100 text-decoration-none d-flex flex-row align-items-center gap-3\"><i class=\"bi bi-arrow-counterclockwise fs-3 text-warning\"></i><span><strong class=\"d-block\">Refund Policy</strong><small class=\"text-secondary\">Our 30-day money-back guarantee</small></span></a></div>\n  <div class=\"col-md-6\"><a href=\"contact.php\" class=\"card p-3 h-100 text-decoration-none d-flex flex-row align-items-center gap-3\"><i class=\"bi bi-chat-dots-fill fs-3 text-info\"></i><span><strong class=\"d-block\">Contact Us</strong><small class=\"text-secondary\">Get in touch with our team</small></span></a></div>\n</div>\n\n<h2>Frequently Asked Questions</h2>\n\n<h3><span class=\"badge text-bg-primary me-2\"><i class=\"bi bi-box-seam\"></i></span>Orders &amp; Delivery</h3>\n<p><strong>How will I receive my product?</strong> All products are delivered digitally via email. You will receive your license key and download instructions within minutes of purchase.</p>\n<div class=\"alert alert-warning d-flex gap-3 align-items-start\"><i class=\"bi bi-exclamation-triangle-fill fs-4 flex-shrink-0\"></i><div><strong>I haven\'t received my order. What should I do?</strong><ul class=\"mb-0 mt-1\"><li>Check your spam/junk folder</li><li>Verify the email address used at checkout</li><li>Wait up to 24 hours for processing</li><li>Contact our support team if you still haven\'t received it</li></ul></div></div>\n<p><strong>Can I get a physical copy?</strong> We only offer digital delivery. No physical products are shipped.</p>\n\n<h3><span class=\"badge text-bg-success me-2\"><i class=\"bi bi-key\"></i></span>Installation &amp; Activation</h3>\n<p><strong>How do I install my software?</strong> See our <a href=\"page.php?slug=installation-guide\">Installation Guide</a> for detailed step-by-step instructions.</p>\n<div class=\"alert alert-danger d-flex gap-3 align-items-start\"><i class=\"bi bi-x-octagon-fill fs-4 flex-shrink-0\"></i><div><strong>My license key isn\'t working. What should I do?</strong><ul class=\"mb-0 mt-1\"><li>Ensure you\'re entering the key correctly (no extra spaces)</li><li>Make sure you\'re using the right version of the software</li><li>Check our <a href=\"page.php?slug=activation-help\">Activation Help</a> page</li><li>Contact support if issues persist</li></ul></div></div>\n\n<h3><span class=\"badge text-bg-warning text-dark me-2\"><i class=\"bi bi-credit-card\"></i></span>Payments &amp; Refunds</h3>\n<p><strong>What payment methods do you accept?</strong> We accept Visa, Mastercard, American Express, PayPal, Apple Pay, and Google Pay.</p>\n<table class=\"table table-bordered align-middle\" style=\"max-width:560px;\">\n<thead><tr><th>Topic</th><th>Our Policy</th></tr></thead>\n<tbody>\n<tr><td><i class=\"bi bi-arrow-counterclockwise text-warning me-1\"></i>Refund window</td><td>30-day money-back guarantee</td></tr>\n<tr><td><i class=\"bi bi-lightning-charge-fill text-warning me-1\"></i>Delivery time</td><td>Typically 15–30 minutes by email</td></tr>\n<tr><td><i class=\"bi bi-credit-card-fill text-primary me-1\"></i>Billing</td><td>One-time payment — no subscription, no hidden fees</td></tr>\n</tbody>\n</table>\n<p><strong>Can I get a refund?</strong> Yes, we offer a 30-day money-back guarantee. See our <a href=\"page.php?slug=refund-policy\">Refund Policy</a> for details, or start a request on the <a href=\"returns.php\">Return &amp; Refund</a> page.</p>\n\n<div class=\"card p-4 my-4\" style=\"background: rgba(37,99,235,.05);\"><h5 class=\"fw-bold mb-2\"><i class=\"bi bi-building-fill-check text-primary me-2\"></i>About This Store</h5><p class=\"small mb-2\">This website is operated by <strong>Zed Webtech</strong>, an independent reseller of genuine software licenses. We are not Microsoft, Bitdefender, or McAfee; all trademarks belong to their respective owners.</p><div class=\"row small g-2\"><div class=\"col-md-6\"><i class=\"bi bi-geo-alt-fill text-primary me-1\"></i>101 NW 83rd St, Kansas City, MO 64118, United States</div><div class=\"col-md-6\"><i class=\"bi bi-envelope-fill text-primary me-1\"></i><a href=\"mailto:Paynote@zedwebtech.com\">Paynote@zedwebtech.com</a></div><div class=\"col-md-6\"><i class=\"bi bi-telephone-fill text-primary me-1\"></i><a href=\"tel:1-888-632-9902\">1-888-632-9902</a></div><div class=\"col-md-6\"><i class=\"bi bi-clock-fill text-primary me-1\"></i>Mon–Fri 9 AM – 6 PM EST</div></div></div>\n\n<h2>Contact Support</h2>\n<p>Still need help? Our support team is ready to assist:</p>\n<ul>\n<li><strong>Email:</strong> <a href=\"mailto:Paynote@zedwebtech.com\">Paynote@zedwebtech.com</a></li>\n<li><strong>Phone:</strong> <a href=\"tel:1-888-632-9902\">1-888-632-9902</a></li>\n<li><strong>Live Chat:</strong> Available on our website</li>\n<li><strong>Hours:</strong> Monday–Friday, 9 AM – 6 PM EST</li>\n</ul>\n<div class=\"card p-4 mt-4\"><h5 class=\"fw-bold mb-2\">Questions about this policy?</h5><p class=\"small text-secondary mb-2\">If you have any questions about this policy, please contact us.</p><p class=\"small mb-3\"><a href=\"mailto:Paynote@zedwebtech.com\">Paynote@zedwebtech.com</a> <span class=\"text-secondary mx-1\">|</span> <a href=\"tel:1-888-632-9902\">+1 888-632-9902</a></p><div class=\"d-flex gap-2 flex-wrap\"><a href=\"contact.php\" class=\"btn btn-sm btn-primary rounded-pill px-3\">Contact Us</a><a href=\"index.php\" class=\"btn btn-sm btn-outline-primary rounded-pill px-3\">Back to Home</a></div></div>' WHERE slug = 'help-center';
UPDATE pages SET content = '<p class=\"lead\">Follow these step-by-step instructions to install your software.</p>\n\n<h2>Before You Begin</h2>\n<h3>System Requirements</h3>\n<div class=\"row g-3 my-2\">\n  <div class=\"col-md-6\"><div class=\"card p-3 h-100\"><strong class=\"text-primary\"><i class=\"bi bi-file-earmark-word-fill me-2\"></i>For Microsoft Office</strong><ul class=\"small mb-0 mt-2\"><li>Windows 10 or later / macOS 10.14 or later</li><li>4GB RAM (8GB recommended)</li><li>4GB available disk space</li><li>Internet connection for activation</li></ul></div></div>\n  <div class=\"col-md-6\"><div class=\"card p-3 h-100\"><strong class=\"text-primary\"><i class=\"bi bi-windows me-2\"></i>For Windows OS</strong><ul class=\"small mb-0 mt-2\"><li>1 GHz processor</li><li>4GB RAM (8GB for Windows 11)</li><li>64GB storage (Windows 11 requires 64GB+)</li><li>DirectX 12 compatible graphics</li></ul></div></div>\n</div>\n\n<h2>Microsoft Office Installation</h2>\n<h3><span class=\"badge text-bg-primary me-2\">1</span>Download Office</h3>\n<ol><li>Visit <a href=\"https://setup.office.com\" target=\"_blank\" rel=\"noopener\">setup.office.com</a></li><li>Sign in with your Microsoft account (or create one)</li><li>Enter your 25-character product key</li><li>Click \"Install Office\"</li></ol>\n<h3><span class=\"badge text-bg-primary me-2\">2</span>Run the Installer</h3>\n<ol><li>Open the downloaded file</li><li>Click \"Yes\" if prompted by User Account Control</li><li>Wait for Office to download and install</li></ol>\n<div class=\"alert alert-info d-flex gap-3 align-items-start\"><i class=\"bi bi-info-circle-fill fs-4 flex-shrink-0\"></i><div>This may take <strong>15–30 minutes</strong> depending on your internet speed.</div></div>\n<h3><span class=\"badge text-bg-primary me-2\">3</span>Activate Office</h3>\n<ol><li>Open any Office application (Word, Excel, etc.)</li><li>Sign in with your Microsoft account</li><li>Your license will be activated automatically</li></ol>\n\n<h2>Windows Installation</h2>\n<h3><span class=\"badge text-bg-success me-2\">1</span>Create Installation Media</h3>\n<ol><li>Download the Windows Media Creation Tool from Microsoft</li><li>Run the tool and select \"Create installation media\"</li><li>Choose USB flash drive (8GB minimum)</li><li>Follow the prompts to create bootable media</li></ol>\n<h3><span class=\"badge text-bg-success me-2\">2</span>Install Windows</h3>\n<ol><li>Insert the USB drive and restart your computer</li><li>Boot from the USB drive (press F12, F2, or Del during startup)</li><li>Follow the Windows setup wizard</li><li>Enter your product key when prompted</li></ol>\n<h3><span class=\"badge text-bg-success me-2\">3</span>Activate Windows</h3>\n<ol><li>Go to Settings &gt; Update &amp; Security &gt; Activation</li><li>Click \"Change product key\"</li><li>Enter your 25-character license key</li><li>Click \"Next\" to activate</li></ol>\n\n<h2>Troubleshooting</h2>\n<div class=\"alert alert-danger d-flex gap-3 align-items-start\"><i class=\"bi bi-x-octagon-fill fs-4 flex-shrink-0\"></i><div><strong>\"Product key already used\" error</strong><ul class=\"mb-0 mt-1\"><li>Ensure you\'re using a new, unused key</li><li>Contact support if you purchased a new license</li></ul></div></div>\n<div class=\"alert alert-warning d-flex gap-3 align-items-start\"><i class=\"bi bi-exclamation-triangle-fill fs-4 flex-shrink-0\"></i><div><strong>Installation stuck or frozen</strong><ul class=\"mb-0 mt-1\"><li>Check your internet connection</li><li>Disable antivirus temporarily</li><li>Restart the installation</li></ul></div></div>\n<div class=\"alert alert-info d-flex gap-3 align-items-start\"><i class=\"bi bi-info-circle-fill fs-4 flex-shrink-0\"></i><div><strong>Activation failed</strong><ul class=\"mb-0 mt-1\"><li>Verify your product key is entered correctly</li><li>Ensure you have an internet connection</li><li>See our <a href=\"page.php?slug=activation-help\">Activation Help</a> page</li></ul></div></div>\n\n<h2>Need Help?</h2>\n<p>If you encounter any issues:</p>\n<ul>\n<li><strong>Email:</strong> <a href=\"mailto:Paynote@zedwebtech.com\">Paynote@zedwebtech.com</a></li>\n<li><strong>Phone:</strong> <a href=\"tel:1-888-632-9902\">1-888-632-9902</a></li>\n<li><strong>Live Chat:</strong> Available on our website</li>\n</ul>\n<div class=\"card p-4 mt-4\"><h5 class=\"fw-bold mb-2\">Questions about this policy?</h5><p class=\"small text-secondary mb-2\">If you have any questions about this policy, please contact us.</p><p class=\"small mb-3\"><a href=\"mailto:Paynote@zedwebtech.com\">Paynote@zedwebtech.com</a> <span class=\"text-secondary mx-1\">|</span> <a href=\"tel:1-888-632-9902\">+1 888-632-9902</a></p><div class=\"d-flex gap-2 flex-wrap\"><a href=\"contact.php\" class=\"btn btn-sm btn-primary rounded-pill px-3\">Contact Us</a><a href=\"index.php\" class=\"btn btn-sm btn-outline-primary rounded-pill px-3\">Back to Home</a></div></div>' WHERE slug = 'installation-guide';
UPDATE pages SET content = '<p class=\"lead\">Having trouble activating your software? Follow these guides to resolve common activation issues.</p>\n\n<h2>Microsoft Office Activation</h2>\n<h3><i class=\"bi bi-wifi text-success me-2\"></i>Online Activation (Recommended)</h3>\n<ol><li>Open any Office app (Word, Excel, PowerPoint)</li><li>Sign in with your Microsoft account</li><li>Go to File &gt; Account</li><li>Click \"Change License\" or \"Activate Product\"</li><li>Enter your 25-character product key</li><li>Click \"Activate\" and follow the prompts</li></ol>\n<h3><i class=\"bi bi-telephone-fill text-primary me-2\"></i>Phone Activation</h3>\n<p>If online activation fails:</p>\n<ol><li>Open any Office app</li><li>Go to File &gt; Account &gt; Activate Product</li><li>Select \"I want to activate by telephone\"</li><li>Call the number provided</li><li>Follow the automated system to complete activation</li></ol>\n\n<h2>Windows Activation</h2>\n<h3><i class=\"bi bi-wifi text-success me-2\"></i>Activate Windows Online</h3>\n<ol><li>Open Settings (Windows key + I)</li><li>Go to Update &amp; Security &gt; Activation</li><li>Click \"Change product key\"</li><li>Enter your 25-character license key</li><li>Click \"Next\" to activate</li></ol>\n<h3><i class=\"bi bi-telephone-fill text-primary me-2\"></i>Activate Windows by Phone</h3>\n<ol><li>Open Command Prompt as Administrator</li><li>Type: <code>slui 4</code> and press Enter</li><li>Select your country</li><li>Call the provided number</li><li>Follow the automated prompts</li></ol>\n\n<h2>Common Activation Errors</h2>\n<div class=\"alert alert-danger d-flex gap-3 align-items-start\"><i class=\"bi bi-x-octagon-fill fs-4 flex-shrink-0\"></i><div><strong>\"Product key has already been used\"</strong><br><em>Possible causes:</em> key previously activated on another device, or a typing error.<ul class=\"mb-0 mt-1\"><li>Double-check the key is entered correctly</li><li>If purchased from us, contact support with your order number</li><li>We will verify and assist with activation</li></ul></div></div>\n<div class=\"alert alert-warning d-flex gap-3 align-items-start\"><i class=\"bi bi-exclamation-triangle-fill fs-4 flex-shrink-0\"></i><div><strong>\"Product key is not valid\"</strong><br><em>Possible causes:</em> wrong product for the key, or key entered with errors.<ul class=\"mb-0 mt-1\"><li>Verify you\'re installing the correct product version</li><li>Check for similar characters (0 vs O, 1 vs I)</li><li>Remove any extra spaces</li><li>Contact support if the issue persists</li></ul></div></div>\n<div class=\"alert alert-info d-flex gap-3 align-items-start\"><i class=\"bi bi-cloud-slash-fill fs-4 flex-shrink-0\"></i><div><strong>\"Unable to reach activation servers\"</strong><ul class=\"mb-0 mt-1\"><li>Check your internet connection</li><li>Disable VPN if active</li><li>Temporarily disable firewall/antivirus</li><li>Try again later (servers may be busy)</li></ul></div></div>\n\n<h2>Activation Limits</h2>\n<h3>How many devices can I activate?</h3>\n<table class=\"table table-bordered align-middle\" style=\"max-width:520px;\">\n<thead><tr><th>Product</th><th>Activation Limit</th></tr></thead>\n<tbody>\n<tr><td><i class=\"bi bi-house-fill text-primary me-1\"></i>Office Home</td><td><span class=\"badge text-bg-primary\">1 PC or Mac</span></td></tr>\n<tr><td><i class=\"bi bi-briefcase-fill text-primary me-1\"></i>Office Professional</td><td><span class=\"badge text-bg-primary\">1 PC</span></td></tr>\n<tr><td><i class=\"bi bi-windows text-primary me-1\"></i>Windows 10/11</td><td><span class=\"badge text-bg-primary\">1 PC</span></td></tr>\n</tbody>\n</table>\n\n<h2>Contact Support</h2>\n<p>If you\'re still having activation issues:</p>\n<ul>\n<li><strong>Email:</strong> <a href=\"mailto:Paynote@zedwebtech.com\">Paynote@zedwebtech.com</a></li>\n<li><strong>Phone:</strong> <a href=\"tel:1-888-632-9902\">1-888-632-9902</a></li>\n<li><strong>Live Chat:</strong> Available on our website</li>\n</ul>\n<div class=\"alert alert-success d-flex gap-3 align-items-start\"><i class=\"bi bi-lightbulb-fill fs-4 flex-shrink-0\"></i><div><strong>Please have ready:</strong><ul class=\"mb-0 mt-1\"><li>Your order number</li><li>Product key (first 5 characters only)</li><li>Error message received</li></ul></div></div>\n<div class=\"card p-4 mt-4\"><h5 class=\"fw-bold mb-2\">Questions about this policy?</h5><p class=\"small text-secondary mb-2\">If you have any questions about this policy, please contact us.</p><p class=\"small mb-3\"><a href=\"mailto:Paynote@zedwebtech.com\">Paynote@zedwebtech.com</a> <span class=\"text-secondary mx-1\">|</span> <a href=\"tel:1-888-632-9902\">+1 888-632-9902</a></p><div class=\"d-flex gap-2 flex-wrap\"><a href=\"contact.php\" class=\"btn btn-sm btn-primary rounded-pill px-3\">Contact Us</a><a href=\"index.php\" class=\"btn btn-sm btn-outline-primary rounded-pill px-3\">Back to Home</a></div></div>' WHERE slug = 'activation-help';
UPDATE pages SET content = '<p class=\"lead\">Quick answers to the questions we hear most often. Can\'t find yours? <a href=\"contact.php\">Contact us</a> any time.</p>\n\n<h2><span class=\"badge text-bg-primary me-2\"><i class=\"bi bi-box-seam\"></i></span>Orders &amp; Delivery</h2>\n<p><strong>How fast is delivery?</strong> License keys are emailed within 15–30 minutes of payment — usually just a few minutes. No physical shipment, ever.</p>\n<p><strong>Where do I find my key after purchase?</strong> In your order confirmation email, and any time under <a href=\"account.php\">My Account</a> (verify your order email to view orders and keys).</p>\n\n<h2><span class=\"badge text-bg-success me-2\"><i class=\"bi bi-key\"></i></span>Licensing</h2>\n<p><strong>Are these genuine licenses?</strong> Yes — every key is a genuine product license that activates directly with the official vendor (Microsoft, Bitdefender, McAfee).</p>\n<p><strong>Is this a subscription?</strong> No. Unless a product clearly states a term (e.g., antivirus 1-year plans), Office and Windows licenses are one-time purchases for lifetime use on one device.</p>\n<table class=\"table table-bordered align-middle\" style=\"max-width:560px;\">\n<thead><tr><th>License type</th><th>Term</th><th>Devices</th></tr></thead>\n<tbody>\n<tr><td>Office 2019/2021/2024</td><td><span class=\"badge text-bg-success\">Lifetime</span></td><td>1 PC or Mac</td></tr>\n<tr><td>Windows 10/11</td><td><span class=\"badge text-bg-success\">Lifetime</span></td><td>1 PC</td></tr>\n<tr><td>Antivirus plans</td><td><span class=\"badge text-bg-warning text-dark\">1–2 Years</span></td><td>As stated per plan</td></tr>\n</tbody>\n</table>\n\n<h2><span class=\"badge text-bg-warning text-dark me-2\"><i class=\"bi bi-credit-card\"></i></span>Payments &amp; Refunds</h2>\n<p><strong>Which payment methods are accepted?</strong> Visa, Mastercard, American Express, PayPal, Apple Pay, and Google Pay. Payments are processed over a secure encrypted connection.</p>\n<p><strong>What is the refund policy?</strong> A 30-day money-back guarantee applies. Start a request on the <a href=\"returns.php\">Return &amp; Refund</a> page or read the full <a href=\"page.php?slug=refund-policy\">Refund Policy</a>.</p>\n\n<h2><span class=\"badge text-bg-info me-2\"><i class=\"bi bi-headset\"></i></span>Support</h2>\n<div class=\"alert alert-info d-flex gap-3 align-items-start\"><i class=\"bi bi-info-circle-fill fs-4 flex-shrink-0\"></i><div><strong>Free installation help is included with every order.</strong> Email, call, or use live chat and we\'ll walk you through setup step by step.</div></div>\n\n<div class=\"card p-4 my-4\" style=\"background: rgba(37,99,235,.05);\"><h5 class=\"fw-bold mb-2\"><i class=\"bi bi-building-fill-check text-primary me-2\"></i>About This Store</h5><p class=\"small mb-2\">This website is operated by <strong>Zed Webtech</strong>, an independent reseller of genuine software licenses. We are not Microsoft, Bitdefender, or McAfee; all trademarks belong to their respective owners.</p><div class=\"row small g-2\"><div class=\"col-md-6\"><i class=\"bi bi-geo-alt-fill text-primary me-1\"></i>101 NW 83rd St, Kansas City, MO 64118, United States</div><div class=\"col-md-6\"><i class=\"bi bi-envelope-fill text-primary me-1\"></i><a href=\"mailto:Paynote@zedwebtech.com\">Paynote@zedwebtech.com</a></div><div class=\"col-md-6\"><i class=\"bi bi-telephone-fill text-primary me-1\"></i><a href=\"tel:1-888-632-9902\">1-888-632-9902</a></div><div class=\"col-md-6\"><i class=\"bi bi-clock-fill text-primary me-1\"></i>Mon–Fri 9 AM – 6 PM EST</div></div></div>\n<div class=\"card p-4 mt-4\"><h5 class=\"fw-bold mb-2\">Questions about this policy?</h5><p class=\"small text-secondary mb-2\">If you have any questions about this policy, please contact us.</p><p class=\"small mb-3\"><a href=\"mailto:Paynote@zedwebtech.com\">Paynote@zedwebtech.com</a> <span class=\"text-secondary mx-1\">|</span> <a href=\"tel:1-888-632-9902\">+1 888-632-9902</a></p><div class=\"d-flex gap-2 flex-wrap\"><a href=\"contact.php\" class=\"btn btn-sm btn-primary rounded-pill px-3\">Contact Us</a><a href=\"index.php\" class=\"btn btn-sm btn-outline-primary rounded-pill px-3\">Back to Home</a></div></div>' WHERE slug = 'faqs';
UPDATE pages SET content = '<p class=\"lead\">We stand behind every license we sell. If something isn\'t right, here\'s exactly how returns and refunds work.</p>\n\n<div class=\"alert alert-success d-flex gap-3 align-items-start\"><i class=\"bi bi-patch-check-fill fs-4 flex-shrink-0\"></i><div><strong>30-Day Money-Back Guarantee.</strong> If your license cannot be activated and our support team cannot resolve it, you get your money back.</div></div>\n\n<h2>Refund Eligibility</h2>\n<table class=\"table table-bordered align-middle\">\n<thead><tr><th>Scenario</th><th>Eligible?</th><th>What to do</th></tr></thead>\n<tbody>\n<tr><td>Key fails to activate and support can\'t fix it</td><td><span class=\"badge text-bg-success\"><i class=\"bi bi-check-lg\"></i> Yes</span></td><td>Submit a request — full refund</td></tr>\n<tr><td>Bought the wrong edition (key unused)</td><td><span class=\"badge text-bg-success\"><i class=\"bi bi-check-lg\"></i> Yes</span></td><td>We\'ll exchange or refund</td></tr>\n<tr><td>Order not delivered within 24 hours</td><td><span class=\"badge text-bg-success\"><i class=\"bi bi-check-lg\"></i> Yes</span></td><td>Contact support or request refund</td></tr>\n<tr><td>Key already activated successfully</td><td><span class=\"badge text-bg-danger\"><i class=\"bi bi-x-lg\"></i> No</span></td><td>Activated keys can\'t be resold — contact support for help instead</td></tr>\n<tr><td>More than 30 days since purchase</td><td><span class=\"badge text-bg-warning text-dark\"><i class=\"bi bi-dash-lg\"></i> Case-by-case</span></td><td>Contact support — we\'ll do our best</td></tr>\n</tbody>\n</table>\n\n<h2>How to Request a Refund</h2>\n<ol>\n<li>Go to the <a href=\"returns.php\"><strong>Return &amp; Refund Request</strong></a> page</li>\n<li>Enter the email address used for your order and click <em>Find Orders</em></li>\n<li>Click <em>Request Refund</em> next to the order</li>\n<li>Our team reviews the request and responds within 24 hours</li>\n</ol>\n\n<h2>Processing Times</h2>\n<table class=\"table table-bordered align-middle\" style=\"max-width:560px;\">\n<thead><tr><th>Step</th><th>Timeline</th></tr></thead>\n<tbody>\n<tr><td><i class=\"bi bi-inbox-fill text-primary me-1\"></i>Request review</td><td>Within 24 hours</td></tr>\n<tr><td><i class=\"bi bi-check-circle-fill text-success me-1\"></i>Approval &amp; processing</td><td>1–2 business days</td></tr>\n<tr><td><i class=\"bi bi-bank text-primary me-1\"></i>Funds back on your card/PayPal</td><td>3–10 business days (depends on your bank)</td></tr>\n</tbody>\n</table>\n\n<div class=\"alert alert-warning d-flex gap-3 align-items-start\"><i class=\"bi bi-exclamation-triangle-fill fs-4 flex-shrink-0\"></i><div><strong>Please note:</strong> refunds are issued to the original payment method only. We never ask for your card number by email or phone.</div></div>\n\n<div class=\"text-center my-4\"><a href=\"returns.php\" class=\"btn btn-primary rounded-pill px-4 fw-semibold\">Start a Refund Request</a></div>\n\n<div class=\"card p-4 mt-4\"><h5 class=\"fw-bold mb-2\">Questions about this policy?</h5><p class=\"small text-secondary mb-2\">If you have any questions about this policy, please contact us.</p><p class=\"small mb-3\"><a href=\"mailto:Paynote@zedwebtech.com\">Paynote@zedwebtech.com</a> <span class=\"text-secondary mx-1\">|</span> <a href=\"tel:1-888-632-9902\">+1 888-632-9902</a></p><div class=\"d-flex gap-2 flex-wrap\"><a href=\"contact.php\" class=\"btn btn-sm btn-primary rounded-pill px-3\">Contact Us</a><a href=\"index.php\" class=\"btn btn-sm btn-outline-primary rounded-pill px-3\">Back to Home</a></div></div>' WHERE slug = 'returns-refunds';

