UPDATE pages SET content = '<p class=\"lead\">Your privacy matters to us. This policy explains what information we collect, why we collect it, and the choices you have.</p>\n\n<h2><i class=\"bi bi-clipboard-data-fill text-primary me-2\"></i>Information We Collect</h2>\n<table class=\"table table-bordered align-middle\">\n<thead><tr><th>Category</th><th>Examples</th><th>Why we need it</th></tr></thead>\n<tbody>\n<tr><td><strong>Order details</strong></td><td>Name, email, billing country</td><td>To deliver your license and receipt</td></tr>\n<tr><td><strong>Payment data</strong></td><td>Processed by our payment providers</td><td>To complete your purchase securely — we never store card numbers</td></tr>\n<tr><td><strong>Support history</strong></td><td>Messages, chat transcripts</td><td>To resolve your questions faster</td></tr>\n<tr><td><strong>Usage data</strong></td><td>Pages visited, device type</td><td>To improve the store experience</td></tr>\n</tbody>\n</table>\n\n<h2><i class=\"bi bi-gear-fill text-primary me-2\"></i>How We Use Your Information</h2>\n<ul>\n<li>Delivering license keys and order confirmations by email</li>\n<li>Providing installation, activation, and refund support</li>\n<li>Preventing fraud and securing your account</li>\n<li>Improving our website, catalog, and service quality</li>\n</ul>\n\n<div class=\"alert alert-success d-flex gap-3 align-items-start\"><i class=\"bi bi-shield-fill-check fs-4 flex-shrink-0\"></i><div><strong>We never sell your personal information.</strong> Data is shared only with the service providers required to complete your order (payment processing, email delivery) — nothing more. See <a href=\"page.php?slug=do-not-sell\">Do Not Sell My Info</a>.</div></div>\n\n<h2><i class=\"bi bi-person-fill-check text-primary me-2\"></i>Your Rights</h2>\n<table class=\"table table-bordered align-middle\" style=\"max-width:620px;\">\n<thead><tr><th>Right</th><th>What it means</th></tr></thead>\n<tbody>\n<tr><td><span class=\"badge text-bg-primary\">Access</span></td><td>Request a copy of the data we hold about you</td></tr>\n<tr><td><span class=\"badge text-bg-primary\">Correction</span></td><td>Ask us to fix inaccurate information</td></tr>\n<tr><td><span class=\"badge text-bg-primary\">Deletion</span></td><td>Ask us to erase your data, subject to legal retention rules</td></tr>\n<tr><td><span class=\"badge text-bg-primary\">Opt-out</span></td><td>Unsubscribe from marketing at any time</td></tr>\n</tbody>\n</table>\n<p>To exercise any right, email <a href=\"mailto:Paynote@zedwebtech.com\">Paynote@zedwebtech.com</a> — we respond within 30 days.</p>\n\n<h2><i class=\"bi bi-lock-fill text-primary me-2\"></i>Data Security &amp; Retention</h2>\n<p>All traffic is protected with SSL encryption and payments are handled by PCI-compliant providers. Order records are retained only as long as required for accounting and warranty purposes.</p>\n<div class=\"card p-4 mt-4\"><h5 class=\"fw-bold mb-2\">Questions about this policy?</h5><p class=\"small text-secondary mb-2\">If you have any questions about this policy, please contact us.</p><p class=\"small mb-3\"><a href=\"mailto:Paynote@zedwebtech.com\">Paynote@zedwebtech.com</a> <span class=\"text-secondary mx-1\">|</span> <a href=\"tel:1-888-632-9902\">+1 888-632-9902</a></p><div class=\"d-flex gap-2 flex-wrap\"><a href=\"contact.php\" class=\"btn btn-sm btn-primary rounded-pill px-3\">Contact Us</a><a href=\"index.php\" class=\"btn btn-sm btn-outline-primary rounded-pill px-3\">Back to Home</a></div></div>' WHERE slug = 'privacy-policy';
UPDATE pages SET content = '<p class=\"lead\">These terms govern your use of our website and your purchase of software licenses from Zed Webtech. By placing an order, you agree to them.</p>\n\n<h2><span class=\"badge text-bg-primary me-2\">1</span>Who We Are</h2>\n<p>Zed Webtech is an independent reseller of genuine software licenses. We are not Microsoft, Bitdefender, or McAfee; all trademarks belong to their respective owners.</p>\n\n<h2><span class=\"badge text-bg-primary me-2\">2</span>Products &amp; Licensing</h2>\n<table class=\"table table-bordered align-middle\" style=\"max-width:620px;\">\n<thead><tr><th>License type</th><th>Term</th><th>Use rights</th></tr></thead>\n<tbody>\n<tr><td>Office / Windows retail licenses</td><td><span class=\"badge text-bg-success\">Lifetime</span></td><td>1 device unless stated otherwise</td></tr>\n<tr><td>Antivirus subscriptions</td><td><span class=\"badge text-bg-warning text-dark\">Term-based</span></td><td>Devices and duration as stated per plan</td></tr>\n</tbody>\n</table>\n<p>Each license is intended for activation by the purchaser. Resale of keys purchased from us is not permitted.</p>\n\n<h2><span class=\"badge text-bg-primary me-2\">3</span>Orders, Pricing &amp; Delivery</h2>\n<ul>\n<li>Prices are shown in your selected currency and confirmed at checkout</li>\n<li>Delivery is 100% digital — license keys arrive by email, typically within 15–30 minutes</li>\n<li>We may cancel and refund orders flagged by our fraud-prevention checks</li>\n</ul>\n\n<h2><span class=\"badge text-bg-primary me-2\">4</span>Acceptable Use</h2>\n<div class=\"row g-3 my-2\">\n<div class=\"col-md-6\"><div class=\"alert alert-success h-100 mb-0\"><strong><i class=\"bi bi-check-circle-fill me-1\"></i>You may</strong><ul class=\"mb-0 mt-1 small\"><li>Activate your license on the permitted device(s)</li><li>Request support for installation and activation</li><li>Transfer Office to a new device you own (where Microsoft permits)</li></ul></div></div>\n<div class=\"col-md-6\"><div class=\"alert alert-danger h-100 mb-0\"><strong><i class=\"bi bi-x-circle-fill me-1\"></i>You may not</strong><ul class=\"mb-0 mt-1 small\"><li>Resell or redistribute license keys</li><li>Use our content or branding without permission</li><li>Attempt to disrupt or misuse the website</li></ul></div></div>\n</div>\n\n<h2><span class=\"badge text-bg-primary me-2\">5</span>Refunds</h2>\n<p>Our money-back guarantee is described in the <a href=\"page.php?slug=refund-policy\">Refund Policy</a>. Requests can be started on the <a href=\"returns.php\">Return &amp; Refund</a> page.</p>\n\n<h2><span class=\"badge text-bg-primary me-2\">6</span>Liability</h2>\n<div class=\"alert alert-warning d-flex gap-3 align-items-start\"><i class=\"bi bi-exclamation-triangle-fill fs-4 flex-shrink-0\"></i><div>To the maximum extent permitted by law, our liability for any claim related to an order is limited to the amount you paid for that order. We are not liable for indirect or consequential losses.</div></div>\n\n<h2><span class=\"badge text-bg-primary me-2\">7</span>Changes &amp; Governing Law</h2>\n<p>We may update these terms from time to time; the version published here applies to new orders. These terms are governed by the laws of the State of Missouri, USA.</p>\n<div class=\"card p-4 mt-4\"><h5 class=\"fw-bold mb-2\">Questions about this policy?</h5><p class=\"small text-secondary mb-2\">If you have any questions about this policy, please contact us.</p><p class=\"small mb-3\"><a href=\"mailto:Paynote@zedwebtech.com\">Paynote@zedwebtech.com</a> <span class=\"text-secondary mx-1\">|</span> <a href=\"tel:1-888-632-9902\">+1 888-632-9902</a></p><div class=\"d-flex gap-2 flex-wrap\"><a href=\"contact.php\" class=\"btn btn-sm btn-primary rounded-pill px-3\">Contact Us</a><a href=\"index.php\" class=\"btn btn-sm btn-outline-primary rounded-pill px-3\">Back to Home</a></div></div>' WHERE slug = 'terms-of-service';
UPDATE pages SET content = '<p class=\"lead\">We want every purchase to work perfectly. When it doesn\'t, our refund policy keeps things simple and fair.</p>\n\n<div class=\"alert alert-success d-flex gap-3 align-items-start\"><i class=\"bi bi-patch-check-fill fs-4 flex-shrink-0\"></i><div><strong>30-Day Money-Back Guarantee.</strong> If your license cannot be activated and our support team cannot resolve the issue, you receive a full refund.</div></div>\n\n<h2><i class=\"bi bi-list-check text-primary me-2\"></i>Eligibility at a Glance</h2>\n<table class=\"table table-bordered align-middle\">\n<thead><tr><th>Scenario</th><th>Refund</th></tr></thead>\n<tbody>\n<tr><td>Key fails to activate, support cannot fix it</td><td><span class=\"badge text-bg-success\"><i class=\"bi bi-check-lg\"></i> Full refund</span></td></tr>\n<tr><td>Wrong edition purchased — key unused</td><td><span class=\"badge text-bg-success\"><i class=\"bi bi-check-lg\"></i> Exchange or refund</span></td></tr>\n<tr><td>Order not delivered within 24 hours</td><td><span class=\"badge text-bg-success\"><i class=\"bi bi-check-lg\"></i> Full refund</span></td></tr>\n<tr><td>Key already activated successfully</td><td><span class=\"badge text-bg-danger\"><i class=\"bi bi-x-lg\"></i> Not eligible</span></td></tr>\n</tbody>\n</table>\n\n<h2><i class=\"bi bi-clock-history text-primary me-2\"></i>Processing Times</h2>\n<table class=\"table table-bordered align-middle\" style=\"max-width:560px;\">\n<tbody>\n<tr><td><i class=\"bi bi-inbox-fill text-primary me-1\"></i>Request review</td><td>Within 24 hours</td></tr>\n<tr><td><i class=\"bi bi-check-circle-fill text-success me-1\"></i>Approval &amp; processing</td><td>1–2 business days</td></tr>\n<tr><td><i class=\"bi bi-bank text-primary me-1\"></i>Funds returned</td><td>3–10 business days, depending on your bank</td></tr>\n</tbody>\n</table>\n\n<h2><i class=\"bi bi-arrow-right-circle-fill text-primary me-2\"></i>How to Request</h2>\n<ol>\n<li>Open the <a href=\"returns.php\"><strong>Return &amp; Refund Request</strong></a> page</li>\n<li>Enter your order email and click <em>Find Orders</em></li>\n<li>Click <em>Request Refund</em> next to the relevant order</li>\n</ol>\n<div class=\"alert alert-info d-flex gap-3 align-items-start\"><i class=\"bi bi-info-circle-fill fs-4 flex-shrink-0\"></i><div>Refunds are always issued to the original payment method. We will never ask for your card details by email or phone.</div></div>\n<div class=\"card p-4 mt-4\"><h5 class=\"fw-bold mb-2\">Questions about this policy?</h5><p class=\"small text-secondary mb-2\">If you have any questions about this policy, please contact us.</p><p class=\"small mb-3\"><a href=\"mailto:Paynote@zedwebtech.com\">Paynote@zedwebtech.com</a> <span class=\"text-secondary mx-1\">|</span> <a href=\"tel:1-888-632-9902\">+1 888-632-9902</a></p><div class=\"d-flex gap-2 flex-wrap\"><a href=\"contact.php\" class=\"btn btn-sm btn-primary rounded-pill px-3\">Contact Us</a><a href=\"index.php\" class=\"btn btn-sm btn-outline-primary rounded-pill px-3\">Back to Home</a></div></div>' WHERE slug = 'refund-policy';
UPDATE pages SET content = '<p class=\"lead\">Everything we sell is delivered digitally — no boxes, no couriers, no waiting at the door.</p>\n\n<div class=\"alert alert-info d-flex gap-3 align-items-start\"><i class=\"bi bi-send-fill fs-4 flex-shrink-0\"></i><div><strong>100% digital delivery.</strong> No physical products are shipped. Your license key and download instructions arrive by email.</div></div>\n\n<h2><i class=\"bi bi-stopwatch-fill text-primary me-2\"></i>Delivery Timeline</h2>\n<table class=\"table table-bordered align-middle\" style=\"max-width:620px;\">\n<thead><tr><th>Step</th><th>When</th></tr></thead>\n<tbody>\n<tr><td><i class=\"bi bi-receipt text-primary me-1\"></i>Order confirmation</td><td><span class=\"badge text-bg-success\">Instant</span></td></tr>\n<tr><td><i class=\"bi bi-key-fill text-primary me-1\"></i>License key email</td><td><span class=\"badge text-bg-primary\">15–30 minutes</span> (typically much faster)</td></tr>\n<tr><td><i class=\"bi bi-shield-exclamation text-primary me-1\"></i>Orders held for review</td><td>Up to 24 hours in rare cases</td></tr>\n</tbody>\n</table>\n\n<h2><i class=\"bi bi-envelope-open-fill text-primary me-2\"></i>What Your Delivery Email Contains</h2>\n<ul>\n<li>Your 25-character product key</li>\n<li>Official download link for the software</li>\n<li>Step-by-step installation and activation instructions</li>\n<li>Your order number for support reference</li>\n</ul>\n\n<div class=\"alert alert-warning d-flex gap-3 align-items-start\"><i class=\"bi bi-exclamation-triangle-fill fs-4 flex-shrink-0\"></i><div><strong>Haven\'t received your order?</strong><ul class=\"mb-0 mt-1\"><li>Check your spam/junk folder first</li><li>Confirm the email address used at checkout</li><li>View your order any time under <a href=\"account.php\">My Account</a></li><li>Still missing after 24 hours? <a href=\"contact.php\">Contact support</a></li></ul></div></div>\n<div class=\"card p-4 mt-4\"><h5 class=\"fw-bold mb-2\">Questions about this policy?</h5><p class=\"small text-secondary mb-2\">If you have any questions about this policy, please contact us.</p><p class=\"small mb-3\"><a href=\"mailto:Paynote@zedwebtech.com\">Paynote@zedwebtech.com</a> <span class=\"text-secondary mx-1\">|</span> <a href=\"tel:1-888-632-9902\">+1 888-632-9902</a></p><div class=\"d-flex gap-2 flex-wrap\"><a href=\"contact.php\" class=\"btn btn-sm btn-primary rounded-pill px-3\">Contact Us</a><a href=\"index.php\" class=\"btn btn-sm btn-outline-primary rounded-pill px-3\">Back to Home</a></div></div>' WHERE slug = 'shipping-delivery';
UPDATE pages SET content = '<p class=\"lead\">Clear pricing, trusted payment providers, and bank-grade security on every transaction.</p>\n\n<h2><i class=\"bi bi-credit-card-fill text-primary me-2\"></i>Accepted Payment Methods</h2>\n<table class=\"table table-bordered align-middle\" style=\"max-width:620px;\">\n<thead><tr><th>Method</th><th>Notes</th></tr></thead>\n<tbody>\n<tr><td><span class=\"pay-badge me-1\">VISA</span><span class=\"pay-badge me-1\">MC</span><span class=\"pay-badge\">AMEX</span></td><td>All major credit and debit cards</td></tr>\n<tr><td><span class=\"pay-badge\">PayPal</span></td><td>Pay with balance or linked methods</td></tr>\n<tr><td><span class=\"pay-badge me-1\">Apple Pay</span><span class=\"pay-badge\">G Pay</span></td><td>One-tap checkout on supported devices</td></tr>\n</tbody>\n</table>\n\n<h2><i class=\"bi bi-currency-exchange text-primary me-2\"></i>Currencies</h2>\n<p>Prices can be displayed and charged in <strong>USD, EUR, GBP, CAD, and AUD</strong>. Select your currency from the menu in the site header — totals update automatically.</p>\n\n<h2><i class=\"bi bi-shield-lock-fill text-primary me-2\"></i>Payment Security</h2>\n<div class=\"alert alert-success d-flex gap-3 align-items-start\"><i class=\"bi bi-lock-fill fs-4 flex-shrink-0\"></i><div><ul class=\"mb-0\"><li>SSL encryption on every page</li><li>PCI-DSS compliant processing through trusted providers</li><li>We never see or store your full card number</li></ul></div></div>\n\n<h2><i class=\"bi bi-receipt-cutoff text-primary me-2\"></i>Billing Notes</h2>\n<ul>\n<li>Software licenses are <strong>one-time charges</strong> — no auto-renewal, no hidden subscription</li>\n<li>Antivirus plans state their term clearly (e.g., 1 year); they do not renew automatically through us</li>\n<li>Your statement will show a descriptor referencing our store</li>\n<li>Orders flagged by fraud screening may be delayed up to 24 hours or refunded</li>\n</ul>\n<div class=\"card p-4 mt-4\"><h5 class=\"fw-bold mb-2\">Questions about this policy?</h5><p class=\"small text-secondary mb-2\">If you have any questions about this policy, please contact us.</p><p class=\"small mb-3\"><a href=\"mailto:Paynote@zedwebtech.com\">Paynote@zedwebtech.com</a> <span class=\"text-secondary mx-1\">|</span> <a href=\"tel:1-888-632-9902\">+1 888-632-9902</a></p><div class=\"d-flex gap-2 flex-wrap\"><a href=\"contact.php\" class=\"btn btn-sm btn-primary rounded-pill px-3\">Contact Us</a><a href=\"index.php\" class=\"btn btn-sm btn-outline-primary rounded-pill px-3\">Back to Home</a></div></div>' WHERE slug = 'payment-policy';
UPDATE pages SET content = '<p class=\"lead\">We use a small number of cookies to keep the store working smoothly and understand how it is used. Here\'s the full picture.</p>\n\n<h2><i class=\"bi bi-cookie text-primary me-2\"></i>Types of Cookies We Use</h2>\n<table class=\"table table-bordered align-middle\">\n<thead><tr><th>Type</th><th>Purpose</th><th>Duration</th></tr></thead>\n<tbody>\n<tr><td><span class=\"badge text-bg-danger\">Essential</span></td><td>Shopping cart, checkout session, sign-in state</td><td>Session</td></tr>\n<tr><td><span class=\"badge text-bg-primary\">Preferences</span></td><td>Your currency and light/dark theme choice</td><td>Up to 12 months</td></tr>\n<tr><td><span class=\"badge text-bg-info\">Analytics</span></td><td>Anonymous usage statistics that help us improve</td><td>Up to 12 months</td></tr>\n</tbody>\n</table>\n\n<div class=\"alert alert-success d-flex gap-3 align-items-start\"><i class=\"bi bi-shield-fill-check fs-4 flex-shrink-0\"></i><div><strong>No advertising trackers.</strong> We do not use third-party advertising cookies, and we never sell browsing data.</div></div>\n\n<h2><i class=\"bi bi-sliders text-primary me-2\"></i>Managing Cookies</h2>\n<ul>\n<li>Every modern browser lets you block or delete cookies in its privacy settings</li>\n<li>Blocking <strong>essential</strong> cookies may prevent the cart and checkout from working</li>\n<li>Preference cookies simply reset your currency and theme if removed</li>\n</ul>\n\n<p>For more on how we handle data, read our <a href=\"page.php?slug=privacy-policy\">Privacy Policy</a>.</p>\n<div class=\"card p-4 mt-4\"><h5 class=\"fw-bold mb-2\">Questions about this policy?</h5><p class=\"small text-secondary mb-2\">If you have any questions about this policy, please contact us.</p><p class=\"small mb-3\"><a href=\"mailto:Paynote@zedwebtech.com\">Paynote@zedwebtech.com</a> <span class=\"text-secondary mx-1\">|</span> <a href=\"tel:1-888-632-9902\">+1 888-632-9902</a></p><div class=\"d-flex gap-2 flex-wrap\"><a href=\"contact.php\" class=\"btn btn-sm btn-primary rounded-pill px-3\">Contact Us</a><a href=\"index.php\" class=\"btn btn-sm btn-outline-primary rounded-pill px-3\">Back to Home</a></div></div>' WHERE slug = 'cookie-policy';
UPDATE pages SET content = '<p class=\"lead\">Under the California Consumer Privacy Act (CCPA) and similar laws, you have the right to opt out of the sale of your personal information.</p>\n\n<div class=\"alert alert-success d-flex gap-3 align-items-start\"><i class=\"bi bi-shield-fill-check fs-4 flex-shrink-0\"></i><div><strong>Good news: we do not sell personal information.</strong> Not for money, not in exchange for services — period. Your data is used only to fulfil orders and provide support.</div></div>\n\n<h2><i class=\"bi bi-person-fill-lock text-primary me-2\"></i>Your Privacy Rights</h2>\n<table class=\"table table-bordered align-middle\" style=\"max-width:640px;\">\n<thead><tr><th>Right</th><th>Our response time</th></tr></thead>\n<tbody>\n<tr><td><span class=\"badge text-bg-primary\">Know</span> what data we hold about you</td><td>Within 30 days</td></tr>\n<tr><td><span class=\"badge text-bg-primary\">Delete</span> your personal data</td><td>Within 30 days</td></tr>\n<tr><td><span class=\"badge text-bg-primary\">Opt out</span> of any future data sale</td><td>Immediate — already our default</td></tr>\n<tr><td><span class=\"badge text-bg-primary\">Non-discrimination</span> for exercising rights</td><td>Always</td></tr>\n</tbody>\n</table>\n\n<h2><i class=\"bi bi-envelope-paper-fill text-primary me-2\"></i>How to Submit a Request</h2>\n<ol>\n<li>Email <a href=\"mailto:Paynote@zedwebtech.com\">Paynote@zedwebtech.com</a> with the subject \"Privacy Request\"</li>\n<li>Tell us which right you want to exercise</li>\n<li>Include the email address used on your orders so we can verify your identity</li>\n</ol>\n<div class=\"card p-4 mt-4\"><h5 class=\"fw-bold mb-2\">Questions about this policy?</h5><p class=\"small text-secondary mb-2\">If you have any questions about this policy, please contact us.</p><p class=\"small mb-3\"><a href=\"mailto:Paynote@zedwebtech.com\">Paynote@zedwebtech.com</a> <span class=\"text-secondary mx-1\">|</span> <a href=\"tel:1-888-632-9902\">+1 888-632-9902</a></p><div class=\"d-flex gap-2 flex-wrap\"><a href=\"contact.php\" class=\"btn btn-sm btn-primary rounded-pill px-3\">Contact Us</a><a href=\"index.php\" class=\"btn btn-sm btn-outline-primary rounded-pill px-3\">Back to Home</a></div></div>' WHERE slug = 'do-not-sell';
UPDATE pages SET content = '<p class=\"lead\">Please read this disclaimer carefully before using our website or purchasing from our store.</p>\n\n<div class=\"alert alert-info d-flex gap-3 align-items-start\"><i class=\"bi bi-info-circle-fill fs-4 flex-shrink-0\"></i><div><strong>Independent reseller.</strong> Zed Webtech is an independent reseller of genuine software licenses. We are not affiliated with, endorsed by, or sponsored by Microsoft Corporation, Bitdefender, or McAfee. All product names, logos, and brands are property of their respective owners and are used for identification purposes only.</div></div>\n\n<h2><i class=\"bi bi-card-checklist text-primary me-2\"></i>Product Information</h2>\n<ul>\n<li>We make every effort to keep product descriptions, pricing, and availability accurate and current</li>\n<li>Specifications ultimately come from the software vendor and may change without notice</li>\n<li>Screenshots and imagery are illustrative and may differ from the latest software versions</li>\n</ul>\n\n<h2><i class=\"bi bi-link-45deg text-primary me-2\"></i>External Links</h2>\n<p>Our site links to official vendor resources (for example, setup.office.com) for downloads and activation. We are not responsible for the content or availability of external websites.</p>\n\n<h2><i class=\"bi bi-exclamation-octagon-fill text-warning me-2\"></i>Warranty &amp; Liability</h2>\n<div class=\"alert alert-warning d-flex gap-3 align-items-start\"><i class=\"bi bi-exclamation-triangle-fill fs-4 flex-shrink-0\"></i><div>The website and its content are provided \"as is\" without warranties of any kind. Software functionality is warranted by its vendor under the vendor\'s own license terms. Our liability is limited as described in our <a href=\"page.php?slug=terms-of-service\">Terms of Service</a>.</div></div>\n\n<h2><i class=\"bi bi-patch-check-fill text-success me-2\"></i>What We Do Stand Behind</h2>\n<table class=\"table table-bordered align-middle\" style=\"max-width:620px;\">\n<tbody>\n<tr><td><i class=\"bi bi-check-circle-fill text-success me-1\"></i>Genuine, activatable license keys</td></tr>\n<tr><td><i class=\"bi bi-check-circle-fill text-success me-1\"></i>Instant digital delivery by email</td></tr>\n<tr><td><i class=\"bi bi-check-circle-fill text-success me-1\"></i>Free installation &amp; activation support</td></tr>\n<tr><td><i class=\"bi bi-check-circle-fill text-success me-1\"></i>30-day money-back guarantee</td></tr>\n</tbody>\n</table>\n<div class=\"card p-4 mt-4\"><h5 class=\"fw-bold mb-2\">Questions about this policy?</h5><p class=\"small text-secondary mb-2\">If you have any questions about this policy, please contact us.</p><p class=\"small mb-3\"><a href=\"mailto:Paynote@zedwebtech.com\">Paynote@zedwebtech.com</a> <span class=\"text-secondary mx-1\">|</span> <a href=\"tel:1-888-632-9902\">+1 888-632-9902</a></p><div class=\"d-flex gap-2 flex-wrap\"><a href=\"contact.php\" class=\"btn btn-sm btn-primary rounded-pill px-3\">Contact Us</a><a href=\"index.php\" class=\"btn btn-sm btn-outline-primary rounded-pill px-3\">Back to Home</a></div></div>' WHERE slug = 'disclaimer';
